#!/bin/bash
# ═══════════════════════════════════════════════════
#  🫏  مسابقه خرها — اسکریپت نصب کامل
#  فقط این یه فایل رو روی سرور اجرا کن!
#  bash setup.sh
# ═══════════════════════════════════════════════════
set -e

GREEN='\033[0;32m'; YELLOW='\033[1;33m'; RED='\033[0;31m'; NC='\033[0m'; BOLD='\033[1m'

echo ""
echo -e "${BOLD}🫏  مسابقه خرها — نصب خودکار${NC}"
echo "═══════════════════════════════════════"

# ── ۱. Node.js ──────────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۱: بررسی Node.js...${NC}"
if command -v node &>/dev/null; then
  echo -e "${GREEN}✅ Node.js v22.22.2 نصبه${NC}"
else
  echo "   Node.js نصب نیست، در حال نصب..."
  if command -v apt-get &>/dev/null; then
    curl -fsSL https://deb.nodesource.com/setup_20.x | sudo -E bash - 2>/dev/null
    sudo apt-get install -y nodejs 2>/dev/null
  elif command -v yum &>/dev/null; then
    curl -fsSL https://rpm.nodesource.com/setup_20.x | sudo bash - 2>/dev/null
    sudo yum install -y nodejs 2>/dev/null
  else
    echo -e "${RED}❌ نمیتونم Node.js نصب کنم. دستی نصب کن.${NC}"; exit 1
  fi
  echo -e "${GREEN}✅ Node.js v22.22.2 نصب شد${NC}"
fi

# ── ۲. ساخت پوشه ────────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۲: ساخت پوشه بازی...${NC}"
mkdir -p ~/donkey-race
cd ~/donkey-race
echo -e "${GREEN}✅ پوشه ~/donkey-race ساخته شد${NC}"

# ── ۳. نوشتن فایل‌ها ────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۳: نوشتن فایل‌های بازی...${NC}"

echo "" | base64 -d > server.js
echo -e "${GREEN}✅ server.js نوشته شد${NC}"

echo "" | base64 -d > index.html
echo -e "${GREEN}✅ index.html نوشته شد${NC}"

# ── ۴. فایروال ──────────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۴: باز کردن پورت 3000...${NC}"
if command -v ufw &>/dev/null; then
  sudo ufw allow 3000/tcp 2>/dev/null && echo -e "${GREEN}✅ پورت 3000 باز شد (ufw)${NC}" || echo "   (ufw خطا داد، ادامه میدیم)"
elif command -v firewall-cmd &>/dev/null; then
  sudo firewall-cmd --permanent --add-port=3000/tcp 2>/dev/null
  sudo firewall-cmd --reload 2>/dev/null
  echo -e "${GREEN}✅ پورت 3000 باز شد (firewalld)${NC}"
else
  echo "   فایروال شناخته‌نشده — پورت رو دستی باز کن"
fi

# ── ۵. pm2 ──────────────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۵: نصب pm2 (برای اجرای همیشگی)...${NC}"
if command -v pm2 &>/dev/null; then
  echo -e "${GREEN}✅ pm2 قبلاً نصبه${NC}"
else
  sudo npm install -g pm2 2>/dev/null && echo -e "${GREEN}✅ pm2 نصب شد${NC}" || echo "   pm2 نصب نشد، بدون اون هم کار میکنه"
fi

# ── ۶. اجرا ─────────────────────────────────────
echo -e "\n${YELLOW}▶ مرحله ۶: راه‌اندازی بازی...${NC}"
cd ~/donkey-race

if command -v pm2 &>/dev/null; then
  pm2 delete donkey-race 2>/dev/null || true
  pm2 start server.js --name donkey-race 2>/dev/null
  pm2 save 2>/dev/null
  # try to setup startup (non-fatal)
  PM2_STARTUP=$(pm2 startup 2>/dev/null | tail -1)
  if [[ "$PM2_STARTUP" == sudo* ]]; then eval "$PM2_STARTUP" 2>/dev/null || true; fi
  echo -e "${GREEN}✅ بازی با pm2 اجرا شد (بعد از ریبوت هم روشنه)${NC}"
else
  nohup node server.js > ~/donkey-race/game.log 2>&1 &
  echo $! > ~/donkey-race/game.pid
  echo -e "${GREEN}✅ بازی اجرا شد (pid: $(cat ~/donkey-race/game.pid))${NC}"
fi

# ── نتیجه ───────────────────────────────────────
sleep 1
SERVER_IP=$(curl -s --max-time 3 ifconfig.me 2>/dev/null || hostname -I | awk '{print $1}')

echo ""
echo "═══════════════════════════════════════"
echo -e "${BOLD}${GREEN}🎉 نصب تموم شد!${NC}"
echo ""
echo -e "  🌐 لینک بازی:"
echo -e "  ${BOLD}http://${SERVER_IP}:3000${NC}"
echo ""
echo -e "  این لینک رو به دوستات بده!"
echo ""
echo "  دستورات مفید:"
echo "  pm2 status               ← وضعیت سرور"
echo "  pm2 logs donkey-race     ← لاگ‌ها"
echo "  pm2 restart donkey-race  ← ریستارت"
echo "═══════════════════════════════════════"
